/**
 * @fileoverview CalendarView Shift+drag interaction layer.
 *
 * Provides:
 *   - Shift+drag on empty cells → date/time range selection → add event
 *   - Shift+drag on event blocks (time-grid) → move event time → confirmation
 *   - Shift+drag on event chips/bars (month) → move event date → confirmation
 *
 * Bound once on the persistent root element via delegation.
 * Requires CRUD to be installed (`ctx._crudInstalled`).
 *
 * @module module/CalendarView/features/interactions
 */

import razyui from '../../../index.js';

/**
 * Install Shift+drag interactions on a CalendarView.
 *
 * @param {Object} ctx — CRUD context bridge (same object installCrud receives)
 */
export function installInteractions(ctx) {
    const root = ctx.root;    const signal = ctx.signal;    let drag = null;

    // ── Pointer-down: decide what action to start ────────────

    root.addEventListener('pointerdown', (e) => {
        if (!ctx._crudInstalled) return;

        // 0) Resize handle on event block (no Shift required)
        const resizeHandle = e.target.closest('.cal-event-resize-top, .cal-event-resize-bottom');
        if (resizeHandle) {
            const block = resizeHandle.closest('.cal-event-block');
            const gridBody = razyui(root).find('.cal-tg-body')[0];
            if (block && gridBody) {
                e.preventDefault();
                e.stopPropagation();
                const edge = razyui(resizeHandle).hasClass('cal-event-resize-top') ? 'top' : 'bottom';
                const ev = ctx.events.find(x => x.id === block.dataset.calEventId);
                if (ev) beginTimeResize(e, ev, block, gridBody, edge);
                return;
            }
        }

        // 0b) Resize handle on month bar (no Shift required)
        const monthResizeHandle = e.target.closest('.cal-event-resize-left, .cal-event-resize-right');
        if (monthResizeHandle) {
            const bar = monthResizeHandle.closest('.cal-event-bar');
            if (bar) {
                e.preventDefault();
                e.stopPropagation();
                const edge = razyui(monthResizeHandle).hasClass('cal-event-resize-left') ? 'start' : 'end';
                const ev = ctx.events.find(x => x.id === bar.dataset.calEventId);
                if (ev) beginMonthResize(e, ev, bar, edge);
                return;
            }
        }

        // 1) Event block / chip / bar → move event (no Shift required)
        const eventEl = e.target.closest('[data-cal-event-id]');
        if (eventEl) {
            e.preventDefault();
            e.stopPropagation();
            beginEventDrag(e, eventEl);
            return;
        }

        if (!e.shiftKey) return;

        // 2) Time-grid cell → time-range select
        const tgCell = e.target.closest('.cal-tg-cell');
        if (tgCell?.dataset.calDate) {
            e.preventDefault();
            e.stopPropagation();
            beginRangeSelect(e, '.cal-tg-cell');
            return;
        }

        // 3) Month cell → date-range select
        const mCell = e.target.closest('.cal-month-cell');
        if (mCell?.dataset.calDate) {
            e.preventDefault();
            e.stopPropagation();
            beginRangeSelect(e, '.cal-month-cell');
            return;
        }
    }, { signal });

    // ══════════════════════════════════════════════════════════
    //  RANGE SELECTION  (Shift+drag across empty cells)
    // ══════════════════════════════════════════════════════════

    function beginRangeSelect(e, selector) {
        const cell = e.target.closest(selector);
        if (!cell) return;

        const anchorMs = Number(cell.dataset.calDate);
        drag = {
            kind: 'range',
            selector,
            anchorMs,
            currentMs: anchorMs,
            highlighted: new Set(),
        };

        syncHighlight();
        document.addEventListener('pointermove', onRangeMove, { signal });
        document.addEventListener('pointerup', onRangeUp, { once: true, signal });
    }

    function onRangeMove(e) {
        if (!drag || drag.kind !== 'range') return;
        const el = document.elementFromPoint(e.clientX, e.clientY);
        const cell = el?.closest(drag.selector);
        if (cell?.dataset.calDate) {
            drag.currentMs = Number(cell.dataset.calDate);
            syncHighlight();
        }
    }

    function syncHighlight() {
        drag.highlighted.forEach(c => razyui(c).removeClass('is-range-selecting'));
        drag.highlighted.clear();

        const lo = Math.min(drag.anchorMs, drag.currentMs);
        const hi = Math.max(drag.anchorMs, drag.currentMs);

        razyui(root).find(`${drag.selector}[data-cal-date]`).each(c => {
            const ms = Number(c.dataset.calDate);
            if (ms >= lo && ms <= hi) {
                razyui(c).addClass('is-range-selecting');
                drag.highlighted.add(c);
            }
        });
    }

    function onRangeUp() {
        document.removeEventListener('pointermove', onRangeMove);
        if (!drag || drag.kind !== 'range') return;

        // Clear highlights
        drag.highlighted.forEach(c => razyui(c).removeClass('is-range-selecting'));

        const lo = Math.min(drag.anchorMs, drag.currentMs);
        const hi = Math.max(drag.anchorMs, drag.currentMs);
        const isTimeGrid = drag.selector === '.cal-tg-cell';
        drag = null;

        const start = new Date(lo);
        let end;
        if (isTimeGrid) {
            end = new Date(hi + 3600000);        // cell = 1 h → include next hour
        } else {
            end = new Date(hi);
            end.setHours(23, 59, 0, 0);          // month cell → end-of-day inclusive
        }

        if (ctx.showAddDialog) ctx.showAddDialog(start, end);
    }

    // ══════════════════════════════════════════════════════════
    //  EVENT DRAG  (Shift+drag on an existing event)
    // ══════════════════════════════════════════════════════════

    function beginEventDrag(e, eventEl) {
        const ev = ctx.events.find(x => x.id === eventEl.dataset.calEventId);
        if (!ev) return;

        // Time-grid block → vertical (+ cross-column) drag
        const block = eventEl.closest('.cal-event-block');
        const gridBody = razyui(root).find('.cal-tg-body')[0];
        if (block && gridBody) {
            beginTimeDrag(e, ev, block, gridBody);
            return;
        }

        // Month chip / bar → drag across day cells
        if (eventEl.closest('.cal-month-cell') || razyui(eventEl).hasClass('cal-event-bar')) {
            beginMonthDrag(e, ev, eventEl);
        }
    }

    // ── Time-grid event drag ──────────────────────────────────

    function beginTimeDrag(e, ev, block, gridBody) {
        const dayStartH = ctx.config.dayStartHour || 0;
        const dayEndH   = ctx.config.dayEndHour || 24;
        const totalH    = dayEndH - dayStartH;
        const bodyRect  = gridBody.getBoundingClientRect();
        const pxPerHour = bodyRect.height / totalH;
        const duration  = ev.end.getTime() - ev.start.getTime();

        const cols     = Array.from(razyui(root).find('.cal-tg-event-col'));
        const colRects = cols.map(c => c.getBoundingClientRect());

        // Detect starting column
        let startCol = 0;
        const br = block.getBoundingClientRect();
        for (let i = 0; i < colRects.length; i++) {
            if (br.left >= colRects[i].left && br.left < colRects[i].right) {
                startCol = i; break;
            }
        }

        drag = {
            kind: 'time-drag',
            event: ev, block,
            startY: e.clientY, startCol, origCol: startCol, cols, colRects,
            pxPerHour, duration, dayStartH, dayEndH, totalH,
            origTop: block.style.top,
            newStart: null, newEnd: null,
        };

        razyui(block).addClass('is-dragging');
        razyui(document.body).css('cursor', 'grabbing');

        document.addEventListener('pointermove', onTimeDragMove, { signal });
        document.addEventListener('pointerup', onTimeDragUp, { once: true, signal });
    }

    function onTimeDragMove(e) {
        const d = drag;
        if (!d || d.kind !== 'time-drag') return;

        const dy = e.clientY - d.startY;
        const origMin = d.event.start.getHours() * 60 + d.event.start.getMinutes();
        let newMin = origMin + (dy / d.pxPerHour) * 60;
        newMin = Math.round(newMin / 15) * 15;                        // snap 15 min

        const maxMin = d.dayEndH * 60 - d.duration / 60000;
        newMin = Math.max(d.dayStartH * 60, Math.min(newMin, maxMin));

        // Column (day) from pointer X
        let col = d.startCol;
        for (let i = 0; i < d.colRects.length; i++) {
            if (e.clientX >= d.colRects[i].left && e.clientX < d.colRects[i].right) {
                col = i; break;
            }
        }

        // Derive column date from first row's cells
        const firstRow  = razyui(root).find('.cal-tg-row')[0];
        const cellsContainer = firstRow ? razyui(firstRow).find('.cal-tg-cells')[0] : null;
        const firstCell = cellsContainer?.children[col];
        const baseDate  = firstCell?.dataset.calDate
            ? new Date(Number(firstCell.dataset.calDate))
            : new Date(d.event.start);

        const ns = new Date(
            baseDate.getFullYear(), baseDate.getMonth(), baseDate.getDate(),
            Math.floor(newMin / 60), newMin % 60, 0, 0,
        );
        d.newStart = ns;
        d.newEnd   = new Date(ns.getTime() + d.duration);

        // Visual: update block position using transform
        const snappedDy = ((newMin - origMin) / 60) * d.pxPerHour;
        const dx = d.colRects[col].left - d.colRects[d.origCol].left;
        razyui(d.block).css('transform', `translate3d(${dx}px, ${snappedDy}px, 0)`);
    }

    function onTimeDragUp() {
        document.removeEventListener('pointermove', onTimeDragMove);
        razyui(document.body).css('cursor', '');

        const d = drag;
        if (!d || d.kind !== 'time-drag') return;

        const $block = razyui(d.block);
        $block.removeClass('is-dragging').css('transform', '');
        drag = null;

        if (!d.newStart || d.newStart.getTime() === d.event.start.getTime()) return;
        showMoveConfirm(d.event, d.newStart, d.newEnd);
    }

    // ── Month-view event drag ─────────────────────────────────

    function beginMonthDrag(e, ev, el) {
        const startCell = el.closest('.cal-month-cell');

        // For multi-day bars that sit outside month cells, use the event start date as anchor
        let anchorMs;
        if (startCell?.dataset.calDate) {
            anchorMs = Number(startCell.dataset.calDate);
        } else {
            // Bar is not inside a cell — compute anchor from event start date (midnight)
            const s = ev.start;
            anchorMs = new Date(s.getFullYear(), s.getMonth(), s.getDate()).getTime();
        }

        drag = {
            kind: 'month-drag',
            event: ev, element: el,
            anchorMs,
            currentMs: anchorMs,
            duration: ev.end.getTime() - ev.start.getTime(),
        };

        razyui(el).css('opacity', '0.6');
        razyui(document.body).css('cursor', 'grabbing');

        document.addEventListener('pointermove', onMonthDragMove, { signal });
        document.addEventListener('pointerup', onMonthDragUp, { once: true, signal });
    }

    function onMonthDragMove(e) {
        if (!drag || drag.kind !== 'month-drag') return;
        const el = document.elementFromPoint(e.clientX, e.clientY);
        const cell = el?.closest('.cal-month-cell');
        if (cell?.dataset.calDate) {
            razyui(root).find('.cal-month-cell.is-drag-target').removeClass('is-drag-target');
            razyui(cell).addClass('is-drag-target');
            drag.currentMs = Number(cell.dataset.calDate);
        }
    }

    function onMonthDragUp() {
        document.removeEventListener('pointermove', onMonthDragMove);
        razyui(document.body).css('cursor', '');

        razyui(root).find('.cal-month-cell.is-drag-target').removeClass('is-drag-target');

        const d = drag;
        if (!d || d.kind !== 'month-drag') return;
        razyui(d.element).css('opacity', '');
        drag = null;

        if (d.currentMs === d.anchorMs) return;

        const delta = d.currentMs - d.anchorMs;
        const ns = new Date(d.event.start.getTime() + delta);
        const ne = new Date(d.event.end.getTime() + delta);
        showMoveConfirm(d.event, ns, ne);
    }

    // ══════════════════════════════════════════════════════════
    //  MONTH BAR RESIZE  (drag left/right handle on event bar)
    // ══════════════════════════════════════════════════════════

    function beginMonthResize(e, ev, barEl, edge) {
        // Cache all month cells and their rects for hit-testing
        const cells = Array.from(razyui(root).find('.cal-month-cell[data-cal-date]'));
        const cellData = cells.map(c => ({
            el: c,
            ms: Number(c.dataset.calDate),
            rect: c.getBoundingClientRect(),
        }));

        drag = {
            kind: 'month-resize',
            event: ev,
            bar: barEl,
            edge,               // 'start' or 'end'
            cells: cellData,
            newStart: null,
            newEnd: null,
        };

        razyui(barEl).addClass('is-resizing');
        razyui(document.body).css('cursor', 'ew-resize');

        document.addEventListener('pointermove', onMonthResizeMove, { signal });
        document.addEventListener('pointerup', onMonthResizeUp, { once: true, signal });
    }

    function onMonthResizeMove(e) {
        const d = drag;
        if (!d || d.kind !== 'month-resize') return;

        // Find which cell the pointer is over
        let targetCell = null;
        for (const cd of d.cells) {
            if (e.clientX >= cd.rect.left && e.clientX < cd.rect.right &&
                e.clientY >= cd.rect.top  && e.clientY < cd.rect.bottom) {
                targetCell = cd;
                break;
            }
        }
        if (!targetCell) return;

        // Highlight target cell
        razyui(root).find('.cal-month-cell.is-drag-target').removeClass('is-drag-target');
        razyui(targetCell.el).addClass('is-drag-target');

        const dayOf = dt => new Date(dt.getFullYear(), dt.getMonth(), dt.getDate()).getTime();

        if (d.edge === 'start') {
            // Can't move start past end date
            const endMs = dayOf(d.event.end);
            if (targetCell.ms <= endMs) {
                const td = new Date(targetCell.ms);
                d.newStart = new Date(
                    td.getFullYear(), td.getMonth(), td.getDate(),
                    d.event.start.getHours(), d.event.start.getMinutes(),
                    d.event.start.getSeconds(),
                );
                d.newEnd = d.event.end;
            }
        } else {
            // Can't move end before start date
            const startMs = dayOf(d.event.start);
            if (targetCell.ms >= startMs) {
                const td = new Date(targetCell.ms);
                d.newEnd = new Date(
                    td.getFullYear(), td.getMonth(), td.getDate(),
                    d.event.end.getHours(), d.event.end.getMinutes(),
                    d.event.end.getSeconds(),
                );
                d.newStart = d.event.start;
            }
        }
    }

    function onMonthResizeUp() {
        document.removeEventListener('pointermove', onMonthResizeMove);
        razyui(document.body).css('cursor', '');

        razyui(root).find('.cal-month-cell.is-drag-target').removeClass('is-drag-target');

        const d = drag;
        if (!d || d.kind !== 'month-resize') return;

        razyui(d.bar).removeClass('is-resizing');
        drag = null;

        if (!d.newStart || !d.newEnd) return;
        if (d.newStart.getTime() === d.event.start.getTime() &&
            d.newEnd.getTime() === d.event.end.getTime()) return;

        showResizeConfirm(d.event, d.newStart, d.newEnd);
    }

    // ── Move-confirmation dialog ──────────────────────────────

    // ══════════════════════════════════════════════════════════
    //  TIME RESIZE  (drag top/bottom handle on event block)
    // ══════════════════════════════════════════════════════════

    function beginTimeResize(e, ev, block, gridBody, edge) {
        const dayStartH = ctx.config.dayStartHour || 0;
        const dayEndH   = ctx.config.dayEndHour || 24;
        const totalH    = dayEndH - dayStartH;
        const bodyRect  = gridBody.getBoundingClientRect();
        const pxPerHour = bodyRect.height / totalH;

        drag = {
            kind: 'time-resize',
            event: ev, block, edge,
            startY: e.clientY,
            pxPerHour, dayStartH, dayEndH, totalH,
            bodyTop: bodyRect.top,
            origStartMin: ev.start.getHours() * 60 + ev.start.getMinutes(),
            origEndMin: ev.end.getHours() * 60 + ev.end.getMinutes(),
            newStart: null, newEnd: null,
        };

        razyui(block).addClass('is-resizing');
        razyui(document.body).css('cursor', edge === 'top' ? 'n-resize' : 's-resize');

        document.addEventListener('pointermove', onTimeResizeMove, { signal });
        document.addEventListener('pointerup', onTimeResizeUp, { once: true, signal });
    }

    function onTimeResizeMove(e) {
        const d = drag;
        if (!d || d.kind !== 'time-resize') return;

        const totalMin = d.totalH * 60;
        const dayStartMin = d.dayStartH * 60;
        const dayEndMin = d.dayEndH * 60;

        // Convert pointer Y to minutes-of-day
        const relY = e.clientY - d.bodyTop;
        let pointedMin = dayStartMin + (relY / d.pxPerHour) * 60;
        pointedMin = Math.round(pointedMin / 15) * 15;   // snap 15 min
        pointedMin = Math.max(dayStartMin, Math.min(pointedMin, dayEndMin));

        let startMin, endMin;
        if (d.edge === 'top') {
            startMin = Math.min(pointedMin, d.origEndMin - 15);  // at least 15 min
            endMin = d.origEndMin;
        } else {
            startMin = d.origStartMin;
            endMin = Math.max(pointedMin, d.origStartMin + 15);  // at least 15 min
        }

        // Clamp
        startMin = Math.max(dayStartMin, startMin);
        endMin = Math.min(dayEndMin, endMin);

        // Compute new dates
        const baseDate = new Date(d.event.start);
        baseDate.setHours(0, 0, 0, 0);
        d.newStart = new Date(baseDate.getTime() + startMin * 60000);
        d.newEnd   = new Date(baseDate.getTime() + endMin * 60000);

        // Update visual
        const topPct = ((startMin - dayStartMin) / totalMin) * 100;
        const heightPct = ((endMin - startMin) / totalMin) * 100;
        razyui(d.block).css({ top: `${topPct}%`, height: `${heightPct}%` });

        // Update time label in block
        const fmtT = m => {
            const h = Math.floor(m / 60), mn = m % 60;
            return `${String(h).padStart(2, '0')}:${String(mn).padStart(2, '0')}`;
        };
        const timeEl = razyui(d.block).find('.cal-event-block-time')[0];
        if (timeEl) razyui(timeEl).text(`${fmtT(startMin)} – ${fmtT(endMin)}`);
    }

    function onTimeResizeUp() {
        document.removeEventListener('pointermove', onTimeResizeMove);
        razyui(document.body).css('cursor', '');

        const d = drag;
        if (!d || d.kind !== 'time-resize') return;

        razyui(d.block).removeClass('is-resizing');
        drag = null;

        if (!d.newStart || (d.newStart.getTime() === d.event.start.getTime() && d.newEnd.getTime() === d.event.end.getTime())) return;
        showResizeConfirm(d.event, d.newStart, d.newEnd);
    }

    async function showResizeConfirm(event, newStart, newEnd) {
        const Dialog = await ctx.razyui.load('Dialog');
        const p = n => String(n).padStart(2, '0');
        const ft = d => `${p(d.getHours())}:${p(d.getMinutes())}`;
        const fd = d => `${d.getMonth() + 1}/${d.getDate()}`;

        const multiDay = newStart.toDateString() !== newEnd.toDateString();
        const msg = multiDay
            ? `Resize "${event.title}" to ${fd(newStart)} – ${fd(newEnd)}?`
            : `Resize "${event.title}" to ${ft(newStart)} – ${ft(newEnd)}?`;
        const ok = await Dialog.confirm('Resize Event', msg, { size: 'sm' });

        if (ok) {
            const events = ctx.events.map(x =>
                x.id === event.id ? { ...x, start: newStart, end: newEnd } : x
            );
            ctx.setEvents(events);

            const cb = ctx.config.crud?.onAfterEdit;
            if (typeof cb === 'function') cb({ ...event, start: newStart, end: newEnd }, null);
        } else {
            ctx.render();
        }
    }

    // ── Move-confirmation dialog (Shift+drag) ─────────────────

    async function showMoveConfirm(event, newStart, newEnd) {
        const Dialog = await ctx.razyui.load('Dialog');
        const p = n => String(n).padStart(2, '0');
        const ft = d => `${p(d.getHours())}:${p(d.getMinutes())}`;
        const fd = d => `${d.getMonth() + 1}/${d.getDate()}`;

        const sameDay = event.start.toDateString() === newStart.toDateString();
        const msg = sameDay
            ? `Move "${event.title}" from ${ft(event.start)}–${ft(event.end)} to ${ft(newStart)}–${ft(newEnd)}?`
            : `Move "${event.title}" from ${fd(event.start)} ${ft(event.start)} to ${fd(newStart)} ${ft(newStart)}?`;

        const ok = await Dialog.confirm('Move Event', msg, { size: 'sm' });

        if (ok) {
            // Update event in-place via setEvents (single re-render)
            const events = ctx.events.map(x =>
                x.id === event.id ? { ...x, start: newStart, end: newEnd } : x
            );
            ctx.setEvents(events);

            const cb = ctx.config.crud?.onAfterEdit;
            if (typeof cb === 'function') cb({ ...event, start: newStart, end: newEnd }, null);
        } else {
            ctx.render();          // revert visual position
        }
    }
}
