/**
 * @fileoverview CalendarView component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * and Custom Element metadata.
 *
 * @module module/CalendarView.def
 */

import razyui from '../index.js';
import { PART } from './CalendarView/constants.js';

/**
 * The definition object for the CalendarView component.
 * Contains metadata, design tokens, state machine configuration, template slots, and custom element details.
 * 
 * @type {Object}
 */
export const CalendarViewDef = {
    /** @type {string} The name of the component. */
    name: 'CalendarView',
    
    /** @type {string} The custom element tag name. */
    tag: 'rui-calendar-view',

    // ═══════════════════════════════════════
    //  Design Tokens
    // ═══════════════════════════════════════
    /**
     * Design tokens for styling the CalendarView component.
     * Defines CSS variables and their default values or references.
     */
    tokens: {
        prefix: 'cal',
        tokens: {
            'radius':            { ref: 'radius.md',           description: 'Container border radius' },
            'header-padding':    { value: '0.5rem 1rem',       description: 'Header padding' },
            'title-font-size':   { value: '1rem',              description: 'Title font size' },
            'title-font-weight': { value: '600',               description: 'Title font weight' },
            'btn-height':        { value: '30px',              description: 'Button height' },
            'btn-padding':       { value: '0 0.5rem',          description: 'Button padding' },
            'btn-radius':        { ref: 'radius.sm',           description: 'Button border radius' },
            'btn-font-size':     { value: '0.8rem',            description: 'Button font size' },
            'accent':            { ref: 'color.accent',        description: 'Accent color' },
            'accent-subtle':     { ref: 'color.accent-subtle', description: 'Accent subtle' },
            'bg':                { ref: 'color.bg',            description: 'Background' },
            'bg-hover':          { ref: 'color.bg-hover',      description: 'Hover background' },
            'bg-inset':          { ref: 'color.bg-inset',      description: 'Inset background' },
            'bg-raised':         { ref: 'color.bg-raised',     description: 'Raised background' },
            'border':            { ref: 'color.border',        description: 'Border color' },
            'border-strong':     { ref: 'color.border-strong', description: 'Strong border' },
            'danger':            { ref: 'color.danger',        description: 'Danger color' },
            'font-stack':        { ref: 'font.family',         description: 'Font family' },
            'on-accent':         { ref: 'color.on-accent',     description: 'Text on accent' },
            'shadow-lg':         { ref: 'shadow.lg',           description: 'Large shadow' },
            'shadow-sm':         { ref: 'shadow.sm',           description: 'Small shadow' },
            'space-sm':          { value: '0.5rem',            description: 'Small spacing' },
            'space-xs':          { value: '0.25rem',           description: 'Extra-small spacing' },
            'text':              { ref: 'color.text',          description: 'Text color' },
            'text-muted':        { ref: 'color.text-muted',    description: 'Muted text color' },
            'text-secondary':    { ref: 'color.text-secondary', description: 'Secondary text' },
        },
    },

    // ═══════════════════════════════════════
    //  State Machine
    // ═══════════════════════════════════════
    /**
     * State machine configuration for managing the calendar's view state (month, week, day).
     */
    states: {
        initial: 'month',
        states: {
            month: {
                on: { SWITCH_WEEK: 'week', SWITCH_DAY: 'day' },
            },
            week: {
                on: { SWITCH_MONTH: 'month', SWITCH_DAY: 'day' },
            },
            day: {
                on: { SWITCH_MONTH: 'month', SWITCH_WEEK: 'week' },
            },
        },
        effects: {
            /**
             * Effect triggered when entering the 'month' state.
             * Updates the active state of the view buttons.
             * 
             * @param {Object} ctx - The state machine context.
             */
            month(ctx) {
                const prev = ctx.root?.querySelector('.cal-view-btn.is-active');
                if (prev) razyui(prev).removeClass('is-active');
                const next = ctx.root?.querySelector('[data-view="month"]');
                if (next) razyui(next).addClass('is-active');
            },
            /**
             * Effect triggered when entering the 'week' state.
             * Updates the active state of the view buttons.
             * 
             * @param {Object} ctx - The state machine context.
             */
            week(ctx) {
                const prev = ctx.root?.querySelector('.cal-view-btn.is-active');
                if (prev) razyui(prev).removeClass('is-active');
                const next = ctx.root?.querySelector('[data-view="week"]');
                if (next) razyui(next).addClass('is-active');
            },
            /**
             * Effect triggered when entering the 'day' state.
             * Updates the active state of the view buttons.
             * 
             * @param {Object} ctx - The state machine context.
             */
            day(ctx) {
                const prev = ctx.root?.querySelector('.cal-view-btn.is-active');
                if (prev) razyui(prev).removeClass('is-active');
                const next = ctx.root?.querySelector('[data-view="day"]');
                if (next) razyui(next).addClass('is-active');
            },
        },
    },

    // ═══════════════════════════════════════
    //  Template Slots
    // ═══════════════════════════════════════
    /**
     * Template slots defining the structure and classes of the calendar elements.
     */
    template: {
        slots: {
            root:      { element: 'div', classes: ['calendar-view'] },
            header:    { element: 'div', classes: ['cal-header'] },
            title:     { element: 'div', classes: ['cal-header-title'] },
            viewBtns:  { element: 'div', classes: ['cal-view-btns'] },
            monthGrid: { element: 'div', classes: ['cal-month-grid'] },
            weekGrid:  { element: 'div', classes: ['cal-tg-body'] },
            dayGrid:   { element: 'div', classes: ['cal-tg-body'] },
        },
    },

    jitParts: {
        [PART.ROOT]: PART.ROOT,
        [PART.HEADER]: PART.HEADER,
        [PART.HEADER_NAV]: PART.HEADER_NAV,
        [PART.TITLE]: PART.TITLE,
        [PART.BTN]: PART.BTN,
        [PART.VIEW_GROUP]: PART.VIEW_GROUP,
        [PART.VIEW_BTN]: PART.VIEW_BTN,
        [PART.MONTH]: PART.MONTH,
        [PART.MONTH_HEAD]: PART.MONTH_HEAD,
        [PART.MONTH_ROW]: PART.MONTH_ROW,
        [PART.MONTH_CELL]: PART.MONTH_CELL,
        [PART.MONTH_WEEKDAY]: PART.MONTH_WEEKDAY,
        [PART.MONTH_BARS]: PART.MONTH_BARS,
        [PART.DAY_NUM]: PART.DAY_NUM,
        [PART.EVENT_CHIP]: PART.EVENT_CHIP,
        [PART.EVENT_MORE]: PART.EVENT_MORE,
        [PART.EVENT_BAR]: PART.EVENT_BAR,
        [PART.EVENT_BLOCK]: PART.EVENT_BLOCK,
        [PART.BLOCK_TITLE]: PART.BLOCK_TITLE,
        [PART.BLOCK_TIME]: PART.BLOCK_TIME,
        [PART.RESIZE_TOP]: PART.RESIZE_TOP,
        [PART.RESIZE_BOTTOM]: PART.RESIZE_BOTTOM,
        [PART.RESIZE_LEFT]: PART.RESIZE_LEFT,
        [PART.RESIZE_RIGHT]: PART.RESIZE_RIGHT,
        [PART.BAR_SPACER]: PART.BAR_SPACER,
        [PART.TIME_GRID]: PART.TIME_GRID,
        [PART.TG_STICKY]: PART.TG_STICKY,
        [PART.TG_HEADER]: PART.TG_HEADER,
        [PART.TG_GUTTER]: PART.TG_GUTTER,
        [PART.TG_HEADER_CELLS]: PART.TG_HEADER_CELLS,
        [PART.TG_COL_HEADER]: PART.TG_COL_HEADER,
        [PART.TG_DAY_NAME]: PART.TG_DAY_NAME,
        [PART.TG_DAY_NUM]: PART.TG_DAY_NUM,
        [PART.TG_SCROLL]: PART.TG_SCROLL,
        [PART.TG_ALLDAY]: PART.TG_ALLDAY,
        [PART.TG_ALLDAY_GUTTER]: PART.TG_ALLDAY_GUTTER,
        [PART.TG_ALLDAY_GRID]: PART.TG_ALLDAY_GRID,
        [PART.TG_BODY]: PART.TG_BODY,
        [PART.TG_ROW]: PART.TG_ROW,
        [PART.TG_TIME_LABEL]: PART.TG_TIME_LABEL,
        [PART.TG_CELLS]: PART.TG_CELLS,
        [PART.TG_CELL]: PART.TG_CELL,
        [PART.TG_OVERLAY]: PART.TG_OVERLAY,
        [PART.TG_EVENT_COL]: PART.TG_EVENT_COL,
        [PART.NOW_LINE]: PART.NOW_LINE,
        [PART.POPUP]: PART.POPUP,
        [PART.POPUP_BAR]: PART.POPUP_BAR,
        [PART.POPUP_CLOSE]: PART.POPUP_CLOSE,
        [PART.POPUP_ACTIONS]: PART.POPUP_ACTIONS,
        [PART.POPUP_ACTION_BTN]: PART.POPUP_ACTION_BTN,
        [PART.POPUP_BODY]: PART.POPUP_BODY,
        [PART.POPUP_TITLE]: PART.POPUP_TITLE,
        [PART.POPUP_DATE]: PART.POPUP_DATE,
        [PART.POPUP_TIME]: PART.POPUP_TIME,
    },

    /* Keyframes and @media cannot be expressed as JIT classes */
    styles: {
        '@keyframes cal-popup-in': {
            'from': { 'opacity': '0', 'transform': 'scale(0.95)' },
            'to':   { 'opacity': '1', 'transform': 'scale(1)' },
        },
        '@media (max-width: 600px)': {
            'root': { '--cal-month-min-h': '0px', 'font-size': '0.8rem' },
            '& .cal-month-row': { 'flex': 'none' },
            '& .cal-header': { 'flex-direction': 'column', 'align-items': 'stretch', 'gap': '6px', 'padding': '8px 10px' },
            '& .cal-header-nav': { 'justify-content': 'center' },
            '& .cal-header-views': { 'justify-content': 'center' },
            '& .cal-header-title': { 'text-align': 'center', 'font-size': '0.9rem' },
            '& .cal-month-cell': { 'min-height': '48px', 'padding': '2px' },
            '& .cal-month-weekday': { 'font-size': '0.62rem', 'padding': '4px 0' },
            '& .cal-day-num': { 'font-size': '0.7rem' },
            '& .cal-event-chip': { 'font-size': '0.6rem', 'padding': '0 3px', 'margin-bottom': '1px' },
            '& .cal-event-more': { 'font-size': '0.6rem', 'padding': '0 2px' },
            '& .cal-month-bars .cal-event-bar': { 'height': '14px', 'line-height': '14px', 'padding': '0 3px', 'font-size': '0.6rem' },
            '& .cal-time-grid': { '--gutter': '36px' },
            '& .cal-tg-time-label': { 'font-size': '0.58rem' },
            '& .cal-tg-time-label span': { 'padding': '1px 3px' },
            '& .cal-tg-col-header': { 'padding': '4px 2px', 'font-size': '0.7rem' },
            '& .cal-tg-day-name': { 'font-size': '0.58rem' },
            '& .cal-tg-day-num': { 'font-size': '0.8rem' },
            '& .cal-tg-row': { 'height': '48px' },
            '& .cal-tg-scroll': { 'max-height': '480px' },
            '& .cal-event-block-title': { 'font-size': '0.65rem' },
            '& .cal-event-block-time': { 'font-size': '0.55rem' },
            '& .cal-popup': { 'width': 'calc(100% - 16px)', 'max-width': '300px', 'left': '8px !important', 'right': '8px !important' },
            '& .cal-btn': { 'height': '28px', 'font-size': '0.75rem' },
            '& .cal-btn.cal-btn-icon': { 'width': '28px', 'height': '28px' },
            '& .cal-view-btn': { 'height': '28px', 'font-size': '0.75rem' },
        },
    },
    // ═══════════════════════════════════════
    //  Custom Element
    // ═══════════════════════════════════════
    ce: {
        tag: 'rui-calendar-view',
        observedAttrs: ['view', 'date', 'locale'],
        attrMap: {
            view:   'view',
            date:   'date',
            locale: 'locale',
        },
    },
};

export default CalendarViewDef;
