/**
 * @fileoverview CalendarView class orchestrator — imports sub-modules.
 *
 * Owns private #fields but delegates to helpers, view builders,
 * event handlers and state management imported from sibling files.
 *
 * @module module/CalendarView/index
 */

import { default as razyui } from '../../index.js';

import { DEFAULTS, PART } from './constants.js';

import {
    startOfDay, startOfWeek, addDays,
    normalizeEvent,
} from './helpers.js';

import { createState } from './state.js';

import {
    buildHeader,
    buildMonthView,
    buildTimeGrid,
    showPopup as viewShowPopup,
} from './view.js';

import {
    goToday, goPrev, goNext,
    fireSlotClick, fireEventClick, fireNavigate,
    startNowLineTimer,
    bindHeaderEvents, bindCalendarBodyEvents, bindPopupClose,
} from './events.js';
import { bindOutsideClick } from '../shared/outsideClick.js';

import { installCrud, showCrudPopup, buildAddButton, installInteractions } from './features/index.js';

// ── CalendarView class ──────────────────────────

const CalendarView = class {
    #el = null;
    #root = null;
    #config = {};
    #stateRef = null;
    #setState = null;
    #events = [];
    #timerHandle = null;
    #popup = null;
    #popupAbort = null;
    #crudCtx = null;
    #cachedHeader = null;
    #cachedBody = null;
    #cachedMonthView = null;
    #cachedWeekView = null;
    #cachedDayView = null;
    #eventAC = new AbortController();
    #destroyed = false;

    constructor(selector, config = {}) {
        this.#config = {
            ...DEFAULTS,
            date: new Date(),
            ...config,
        };

        const el = razyui(selector)[0];
        if (!el) {
            console.warn('CalendarView: element not found \u2192', selector);
            return;
        }
        this.#el = el;

        // Normalise events
        this.#events = (this.#config.events || []).map(ev => normalizeEvent(ev, razyui.hash));

        this.#init();
    }

    // ── Initialisation ──────────────────────

    #init() {
        const el = this.#el;
        const cfg = this.#config;

        // Root container + popup via spell()
        const dom = razyui.spell('div.calendar-view(div.cal-popup)', true);
        const root = dom[0];
        PART.ROOT.apply(root);
        razyui(el).append(root);
        this.#root = root;

        const popup = dom.find('.cal-popup')[0];
        PART.POPUP.apply(popup);
        popup.hidden = true;
        this.#popup = popup;

        // Popup close-button delegation
        bindPopupClose(this.#popup, () => this.#hidePopup());

        // ── Reactive state ──
        const { stateRef, setState, stateSet } = createState(razyui.state, cfg);
        this.#stateRef = stateRef;
        this.#setState = setState;

        // ── CRUD feature — install BEFORE the state effect so the
        //    initial render already has _crudInstalled = true ──
        if (this.#config.crud) {
            this.#crudCtx = this.#buildCrudCtx();
            installCrud(this.#crudCtx);
            installInteractions(this.#crudCtx);
        }

        // Effect: re-render on state change (fires immediately for initial render)
        const self = this;
        stateSet.effect(function () {
            self.#render();
        });

        // Close popup on outside click
        bindOutsideClick(
            this.#popup,
            () => this.#hidePopup(),
            () => this.#popup && !this.#popup.hidden,
            this.#eventAC.signal,
        );

        // Current-time indicator timer
        this.#timerHandle = startNowLineTimer(this.#root, this.#config, razyui);
    }

    /**
     * Build context bridge for the CRUD feature installer.
     * Exposes private fields through getters/setters so crud.js
     * can operate without direct access to #fields.
     */
    #buildCrudCtx() {
        const self = this;
        return {
            get razyui()    { return razyui; },
            get signal()    { return self.#eventAC.signal; },
            get config()    { return self.#config; },
            get events()    { return self.#events; },
            get root()      { return self.#root; },
            get popup()     { return self.#popup; },
            hidePopup()     { self.#hidePopup(); },
            addEvent(ev)    { self.addEvent(ev); },
            removeEvent(id) { self.removeEvent(id); },
            setEvents(evs)  { self.setEvents(evs); },
            render()        { self.#render(); },
            fireCallback(name, ...args) {
                const fn = self.#config[name];
                if (typeof fn === 'function') fn.apply(self, args);
            },
            // Populated by installCrud:
            showAddDialog:  null,
            showEditDialog: null,
            deleteEvent:    null,
            _crudInstalled: false,
        };
    }

    #hidePopup() {
        if (this.#popup) this.#popup.hidden = true;
        if (this.#popupAbort) {
            this.#popupAbort.abort();
            this.#popupAbort = null;
        }
    }

    #showPopup(ev, el) {
        if (this.#crudCtx?._crudInstalled) {
            showCrudPopup(this.#crudCtx, ev, el);
        } else {
            viewShowPopup(this.#popup, ev, el, razyui);
        }
    }

    #fireEventClick(ev) {
        fireEventClick(this.#config, ev);
    }

    #fireSlotClick(d) {
        fireSlotClick(this.#config, d);
    }

    #goToday() {
        goToday(this.#setState, () => fireNavigate(this.#config, this.#stateRef, this));
    }

    #goPrev() {
        goPrev(this.#stateRef, this.#setState, () => fireNavigate(this.#config, this.#stateRef, this));
    }

    #goNext() {
        goNext(this.#stateRef, this.#setState, () => fireNavigate(this.#config, this.#stateRef, this));
    }

    // ── Public API ──────────────────────────

    /**
     * Destroy the CalendarView — abort all listeners, clear timers, remove DOM.
     */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;

        // 1. Abort all signal-managed listeners (document click, interactions, etc.)
        this.#eventAC?.abort();

        // 2. Clear the now-line interval timer
        if (this.#timerHandle != null) {
            clearInterval(this.#timerHandle);
            this.#timerHandle = null;
        }

        // 3. Abort popup AbortController if active
        if (this.#popupAbort) {
            this.#popupAbort.abort();
            this.#popupAbort = null;
        }

        // 4. Remove DOM
        if (this.#root && this.#root.parentNode) {
            this.#root.remove();
        }

        // 5. Null references
        this.#root = null;
        this.#popup = null;
        this.#crudCtx = null;
        this.#cachedHeader = null;
        this.#cachedBody = null;
        this.#cachedMonthView = null;
        this.#cachedWeekView = null;
        this.#cachedDayView = null;
        this.#stateRef = null;
        this.#setState = null;
        this.#events = [];
    }

    /** Change the current view ('month', 'week', 'day'). */
    setView(v) {
        this.#setState({ view: v });
    }

    /** Add an event and re-render. */
    addEvent(ev) {
        this.#events.push(normalizeEvent(ev, razyui.hash));
        this.#render();
    }

    /** Remove an event by ID and re-render. */
    removeEvent(id) {
        const idx = this.#events.findIndex(e => e.id === id);
        if (idx >= 0) { this.#events.splice(idx, 1); this.#render(); }
    }

    /** Replace entire event list and re-render. */
    setEvents(evs) {
        this.#events = (evs || []).map(e => normalizeEvent(e, razyui.hash));
        this.#render();
    }

    /**
     * Return a control object with navigation helpers.
     * @returns {{ prev, next, today, setView, addEvent, removeEvent, setEvents, destroy }}
     */
    getControl() {
        const self = this;
        return {
            get element() { return self.#root; },
            get view()    { return self.#stateRef.view; },
            set view(v)   { self.setView(v); },
            get date()    { return self.#stateRef.date; },
            set date(v)   { self.#setState({ date: v instanceof Date ? v : new Date(v) }); },
            get locale()  { return self.#config.locale; },
            set locale(v) { self.#config.locale = v; self.#render(); },
            prev:        () => self.#goPrev(),
            next:        () => self.#goNext(),
            today:       () => self.#goToday(),
            setView:     (v) => self.setView(v),
            addEvent:    (ev) => self.addEvent(ev),
            removeEvent: (id) => self.removeEvent(id),
            setEvents:   (evs) => self.setEvents(evs),
            destroy:     () => self.destroy(),
            get destroyed() { return self.#destroyed; },
        };
    }

    // ── Rendering ───────────────────────────

    #render() {
        const root = this.#root;

        // Preserve popup across renders
        const popup = this.#popup;
        if (popup) {
            popup.hidden = true;
            popup.remove();
        }

        const view = this.#stateRef.view;
        const date = this.#stateRef.date;

        // Callback bundles
        const headerCbs = {
            goToday: () => this.#goToday(),
            goPrev:  () => this.#goPrev(),
            goNext:  () => this.#goNext(),
            setView: (v) => this.setView(v),
        };

        const viewCbs = {
            showPopup:      (ev, el) => this.#showPopup(ev, el),
            fireEventClick: (ev)     => this.#fireEventClick(ev),
            fireSlotClick:  (d)      => this.#fireSlotClick(d),
        };

        // Header
        if (!this.#cachedHeader) {
            this.#cachedHeader = buildHeader(razyui, date, view, this.#config);
            bindHeaderEvents(this.#cachedHeader, headerCbs);

            // CRUD: Add button in header
            if (this.#crudCtx?._crudInstalled) {
                const addBtn = buildAddButton(razyui);
                const nav = razyui(this.#cachedHeader).find('.cal-header-nav')[0];
                if (nav) razyui(nav).append(addBtn[0]);
                addBtn.on('click', () => {
                    this.#crudCtx.showAddDialog(this.#stateRef.date);
                });
            }
            razyui(root).append(this.#cachedHeader);
        } else {
            buildHeader(razyui, date, view, this.#config, this.#cachedHeader);
        }

        // Body
        if (!this.#cachedBody) {
            this.#cachedBody = razyui.el('div', { className: 'cal-body' })[0];
            razyui(root).append(this.#cachedBody);

            bindCalendarBodyEvents(this.#cachedBody, () => this.#events, viewCbs);

            // CRUD: double-click on slot  add, double-click on event  edit
            if (this.#crudCtx?._crudInstalled) {
                const crudCtx = this.#crudCtx;
                razyui(this.#cachedBody).on('dblclick', (e) => {
                    // Double-click on event  edit
                    const eventEl = e.target.closest('[data-cal-event-id]');
                    if (eventEl) {
                        e.stopPropagation();
                        const ev = this.#events.find(x => x.id === eventEl.dataset.calEventId);
                        if (ev) {
                            this.#hidePopup();
                            crudCtx.showEditDialog(ev);
                        }
                        return;
                    }

                    // Double-click on month cell  add event on that date
                    const monthCell = e.target.closest('.cal-month-cell');
                    if (monthCell?.dataset.calDate) {
                        e.stopPropagation();
                        crudCtx.showAddDialog(new Date(Number(monthCell.dataset.calDate)));
                        return;
                    }

                    // Double-click on time-grid cell  add event at that time
                    const timeCell = e.target.closest('.cal-tg-cell');
                    if (timeCell?.dataset.calDate) {
                        e.stopPropagation();
                        crudCtx.showAddDialog(new Date(Number(timeCell.dataset.calDate)));
                        return;
                    }
                });
            }
        }

        // Clear body contents except the active view
        if (this.#cachedMonthView && this.#cachedMonthView.parentNode) this.#cachedMonthView.remove();
        if (this.#cachedWeekView && this.#cachedWeekView.parentNode) this.#cachedWeekView.remove();
        if (this.#cachedDayView && this.#cachedDayView.parentNode) this.#cachedDayView.remove();

        if (view === 'month') {
            this.#cachedMonthView = buildMonthView(razyui, date, this.#events, this.#config, this.#cachedMonthView);
            razyui(this.#cachedBody).append(this.#cachedMonthView);
        } else if (view === 'week') {
            const wStart = startOfWeek(date, this.#config.weekStartsOn);
            this.#cachedWeekView = buildTimeGrid(razyui, wStart, 7, this.#events, this.#config, this.#cachedWeekView);
            razyui(this.#cachedBody).append(this.#cachedWeekView);
        } else if (view === 'day') {
            this.#cachedDayView = buildTimeGrid(razyui, startOfDay(date), 1, this.#events, this.#config, this.#cachedDayView);
            razyui(this.#cachedBody).append(this.#cachedDayView);
        }

        // Re-attach popup
        if (popup) razyui(root).append(popup);
    }
}

export default CalendarView;
