/**
 * @fileoverview CalendarView DOM construction — header, month/week/day grids, popup.
 * @module module/CalendarView/view
 */

import {
    MONTHS, MONTHS_SHORT, WEEKDAYS_SHORT,
    DAY_MS, MAX_VISIBLE_CHIPS, BAR_LANE_HEIGHT, SCROLL_TARGET_HOUR,
    ICON_PREV, ICON_NEXT, ICON_CLOSE, PART,
} from './constants.js';

import {
    pad, formatTime, startOfDay, startOfWeek, addDays,
    sameDay, isDateInRange, getEventsForDay,
    allocateBarLanes, formatDuration,
} from './helpers.js';

import razyui from '../../index.js';

// ── Header ──────────────────────────────────────

/**
 * Build the header bar (today / prev / next, title, view switcher).
 *
 * @param {object} razyui
 * @param {Date}   date
 * @param {string} view
 * @param {object} config
 * @returns {HTMLElement}
 */
export function buildHeader(razyui, date, view, config, existingHeader = null) {
    if (existingHeader) {
        const $title = razyui(existingHeader).find('.cal-header-title');
        if (view === 'month') {
            $title.text(`${MONTHS[date.getMonth()]} ${date.getFullYear()}`);
        } else if (view === 'week') {
            const wStart = startOfWeek(date, config.weekStartsOn);
            const wEnd = addDays(wStart, 6);
            if (wStart.getMonth() === wEnd.getMonth()) {
                $title.text(`${MONTHS_SHORT[wStart.getMonth()]} ${wStart.getDate()} – ${wEnd.getDate()}, ${wStart.getFullYear()}`);
            } else {
                $title.text(`${MONTHS_SHORT[wStart.getMonth()]} ${wStart.getDate()} – ${MONTHS_SHORT[wEnd.getMonth()]} ${wEnd.getDate()}, ${wEnd.getFullYear()}`);
            }
        } else {
            $title.text(`${WEEKDAYS_SHORT[date.getDay()]}, ${MONTHS_SHORT[date.getMonth()]} ${date.getDate()}, ${date.getFullYear()}`);
        }

        razyui(existingHeader).find('.cal-view-btn').each(btn => {
            if (btn.dataset.calView === view) {
                razyui(btn).addClass('is-active');
            } else {
                razyui(btn).removeClass('is-active');
            }
        });
        return existingHeader;
    }

    const dom = razyui.spell(
        'div.cal-header(div.cal-header-nav(button.cal-btn,button.cal-btn.cal-btn-icon,button.cal-btn.cal-btn-icon,span.cal-header-title),div.cal-header-views)',
        true
    );
    const header = dom[0];
    PART.HEADER.apply(header);
    const btns = dom.find('.cal-btn');
    btns.forEach(b => PART.BTN.apply(b));

    // Today
    const todayBtn = btns[0];
    todayBtn.type = 'button';
    razyui(todayBtn).text('Today');
    todayBtn.dataset.calAction = 'today';

    // Prev
    const prevBtn = btns[1];
    prevBtn.type = 'button';
    razyui(prevBtn).html(ICON_PREV).setAttr({'aria-label': 'Previous'});
    prevBtn.dataset.calAction = 'prev';

    // Next
    const nextBtn = btns[2];
    nextBtn.type = 'button';
    razyui(nextBtn).html(ICON_NEXT).setAttr({'aria-label': 'Next'});
    nextBtn.dataset.calAction = 'next';

    // Title
    const $title = dom.find('.cal-header-title');
    PART.TITLE.apply($title);
    if (view === 'month') {
        $title.text(`${MONTHS[date.getMonth()]} ${date.getFullYear()}`);
    } else if (view === 'week') {
        const wStart = startOfWeek(date, config.weekStartsOn);
        const wEnd = addDays(wStart, 6);
        if (wStart.getMonth() === wEnd.getMonth()) {
            $title.text(`${MONTHS_SHORT[wStart.getMonth()]} ${wStart.getDate()} – ${wEnd.getDate()}, ${wStart.getFullYear()}`);
        } else {
            $title.text(`${MONTHS_SHORT[wStart.getMonth()]} ${wStart.getDate()} – ${MONTHS_SHORT[wEnd.getMonth()]} ${wEnd.getDate()}, ${wEnd.getFullYear()}`);
        }
    } else {
        $title.text(`${WEEKDAYS_SHORT[date.getDay()]}, ${MONTHS_SHORT[date.getMonth()]} ${date.getDate()}, ${date.getFullYear()}`);
    }

    // View switcher
    const $switcher = razyui(dom.find('.cal-header-views')[0]);
    PART.VIEW_GROUP.apply($switcher);
    ['month', 'week', 'day'].forEach(v => {
        const $btn = PART.VIEW_BTN.create({ type: 'button' });
        $btn.text(v.charAt(0).toUpperCase() + v.slice(1));
        if (v === view) $btn.addClass('is-active');
        $btn[0].dataset.calAction = 'view';
        $btn[0].dataset.calView = v;
        $switcher.append($btn);
    });

    const nav = dom.find('.cal-header-nav')[0];
    PART.HEADER_NAV.apply(nav);
    const $header = razyui(header);
    $header.append(nav).append($switcher[0]);

    return header;
}

// ── Month view ──────────────────────────────────

/**
 * Build the month grid.
 *
 * @param {object}   razyui
 * @param {Date}     date
 * @param {Array}    events
 * @param {object}   config
 * @returns {HTMLElement}
 */
export function buildMonthView(razyui, date, events, config, existingContainer = null) {
    const container = existingContainer ? razyui(existingContainer) : PART.MONTH.create();

    const year = date.getFullYear();
    const month = date.getMonth();
    const today = new Date();
    const wso = config.weekStartsOn;

    // Weekday headers
    let headRow = container.find('.cal-month-head')[0];
    if (!headRow) {
        headRow = PART.MONTH_HEAD.create();
        for (let i = 0; i < 7; i++) {
            const d = (i + wso) % 7;
            const cell = PART.MONTH_WEEKDAY.create({ textContent: WEEKDAYS_SHORT[d] });
            headRow.append(cell);
        }
        container.append(headRow);
    } else {
        const $weekdays = razyui(headRow).find('.cal-month-weekday');
        for (let i = 0; i < 7; i++) {
            const d = (i + wso) % 7;
            razyui($weekdays[i]).text(WEEKDAYS_SHORT[d]);
        }
    }

    // Multi-day events
    const multiDayEvts = events.filter(ev => !sameDay(ev.start, ev.end));

    // Grid start
    const firstOfMonth = new Date(year, month, 1);
    const gridStart = startOfWeek(firstOfMonth, wso);

    let rows = container.find('.cal-month-row');

    // 6 rows  7 cols
    for (let row = 0; row < 6; row++) {
        let weekRow = rows[row];
        if (!weekRow) {
            weekRow = PART.MONTH_ROW.create();
            container.append(weekRow);
        } else {
            weekRow = razyui(weekRow);
        }

        const rowStartDate = addDays(gridStart, row * 7);
        const rowStartMs = rowStartDate.getTime();
        const rowEndMs = rowStartMs + 7 * DAY_MS;

        //  Multi-day bars 
        const rowBars = [];
        for (const ev of multiDayEvts) {
            const evStartMs = startOfDay(ev.start).getTime();
            const evEndMs = startOfDay(ev.end).getTime();

            if (evStartMs < rowEndMs && evEndMs >= rowStartMs) {
                const startCol = Math.max(0, Math.round((evStartMs - rowStartMs) / DAY_MS));
                const endCol = Math.min(7, Math.round((evEndMs - rowStartMs) / DAY_MS) + 1);
                if (startCol < endCol) {
                    rowBars.push({
                        event: ev,
                        startCol,
                        endCol,
                        isStart: evStartMs >= rowStartMs,
                        isEnd: evEndMs < rowEndMs,
                    });
                }
            }
        }

        const numLanes = allocateBarLanes(rowBars);

        // Bar overlay layer
        let barLayer = weekRow.find('.cal-month-bars')[0];
        if (!barLayer) {
            barLayer = PART.MONTH_BARS.create();
            weekRow.append(barLayer);
        } else {
            barLayer = razyui(barLayer);
            barLayer.html('');
        }

        if (rowBars.length > 0) {
            for (const bar of rowBars) {
                const barEl = PART.EVENT_BAR.create();
                if (bar.isStart) barEl.addClass('is-start');
                if (bar.isEnd) barEl.addClass('is-end');
                barEl.css({
                    '--ev-color': bar.event.color,
                    '--bar-col': bar.startCol,
                    '--bar-span': bar.endCol - bar.startCol,
                    '--bar-lane': bar.lane,
                });

                if (bar.isStart || bar.startCol === 0) {
                    barEl.text(bar.event.title);
                }

                // Resize handles (left = change start, right = change end)
                if (bar.isStart) {
                    const rl = PART.RESIZE_LEFT.create();
                    barEl.append(rl);
                }
                if (bar.isEnd) {
                    const rr = PART.RESIZE_RIGHT.create();
                    barEl.append(rr);
                }

                barEl.data('calEventId', bar.event.id);
                barLayer.append(barEl);
            }
        }

        //  Day cells 
        let allNextMonth = true;
        let cells = weekRow.find('.' + PART.MONTH_CELL);

        for (let col = 0; col < 7; col++) {
            const cellDate = addDays(gridStart, row * 7 + col);
            let cell = cells[col];
            if (!cell) {
                cell = PART.MONTH_CELL.create();
                weekRow.append(cell);
            } else {
                cell = razyui(cell);
            }

            const isCurrentMonth = cellDate.getMonth() === month;
            cell.attr('class', PART.MONTH_CELL);
            PART.MONTH_CELL.apply(cell);
            if (!isCurrentMonth) cell.addClass('is-outside');
            if (sameDay(cellDate, today)) cell.addClass('is-today');
            if (isCurrentMonth) allNextMonth = false;

            // Day number
            let num = cell.find('.' + PART.DAY_NUM)[0];
            if (!num) {
                num = PART.DAY_NUM.create();
                cell.append(num);
            } else {
                num = razyui(num);
            }
            num.text(cellDate.getDate());

            // Remove old spacer and chips
            cell.find('.cal-bar-spacer, .cal-event-chip, .cal-event-more').detach();

            // Spacer for bar lanes
            if (numLanes > 0) {
                const spacer = PART.BAR_SPACER.create();
                spacer.css('height', `${numLanes * BAR_LANE_HEIGHT}px`);
                cell.append(spacer);
            }

            // Single-day chips
            const dayEvents = getEventsForDay(events, cellDate)
                .filter(ev => sameDay(ev.start, ev.end));
            const isExpandable = dayEvents.length > MAX_VISIBLE_CHIPS;

            const chipsToShow = isExpandable ? dayEvents.slice(0, MAX_VISIBLE_CHIPS) : dayEvents;
            chipsToShow.forEach(ev => {
                const chip = PART.EVENT_CHIP.create({ textContent: ev.title, 'data-cal-event-id': ev.id });
                chip.css('--ev-color', ev.color);
                cell.append(chip);
            });

            if (isExpandable) {
                dayEvents.slice(MAX_VISIBLE_CHIPS).forEach(ev => {
                    const chip = PART.EVENT_CHIP.create({ textContent: ev.title, 'data-cal-event-id': ev.id }).addClass('cal-event-chip-hidden is-overflow');
                    chip.css('--ev-color', ev.color);
                    cell.append(chip);
                });

                const more = PART.EVENT_MORE.create({ textContent: `+ more`, 'data-cal-overflow-count': dayEvents.length - MAX_VISIBLE_CHIPS });
                cell.append(more);
            }

            cell.data('calDate', cellDate.getTime());
        }

        if (row === 5 && allNextMonth) {
            weekRow.css('display', 'none');
        } else {
            weekRow.css('display', '');
        }
    }

    return container[0];
}
//  Time grid (shared by week & day) 

/**
 * Build the scrollable time grid used by week and day views.
 *
 * @param {object}   razyui
 * @param {Date}     startDate
 * @param {number}   numDays
 * @param {Array}    events
 * @param {object}   config
 * @returns {HTMLElement}
 */

/**
 * Create a positioned event block for the time-grid overlay.
 *
 * @param {Function} razyui — razyui factory
 * @param {object}   ev     — normalised event { id, title, start, end, color }
 * @param {number}   startH — grid start hour (e.g. 0)
 * @param {number}   endH   — grid end hour   (e.g. 24)
 * @returns {Elements|null}
 */
function createTimeBlock(razyui, ev, startH, endH) {
    const evStartMin = ev.start.getHours() * 60 + ev.start.getMinutes();
    const evEndMin   = ev.end.getHours()   * 60 + ev.end.getMinutes();
    const gridStart  = startH * 60;
    const gridEnd    = endH   * 60;
    const totalMin   = gridEnd - gridStart;

    if (totalMin <= 0) return null;

    const topPct    = ((Math.max(evStartMin, gridStart) - gridStart) / totalMin) * 100;
    const heightPct = ((Math.min(evEndMin, gridEnd) - Math.max(evStartMin, gridStart)) / totalMin) * 100;

    if (heightPct <= 0) return null;

    const block = PART.EVENT_BLOCK.create({
        'data-cal-event-id': ev.id,
    });
    block.css({ top: `${topPct}%`, height: `${heightPct}%` });

    if (ev.color) block.css('--ev-color', ev.color);

    const bTitle = PART.BLOCK_TITLE.create({ textContent: ev.title });
    block.append(bTitle);
    const bTime = PART.BLOCK_TIME.create({ textContent: formatTime(ev.start) + ' \u2013 ' + formatTime(ev.end) });
    block.append(bTime);
    const rTop = PART.RESIZE_TOP.create();
    block.append(rTop);
    const rBot = PART.RESIZE_BOTTOM.create();
    block.append(rBot);

    return block;
}

export function buildTimeGrid(razyui, startDate, numDays, events, config, existingContainer = null) {
    const container = existingContainer ? razyui(existingContainer) : PART.TIME_GRID.create();
    const startH = config.dayStartHour;
    const endH = config.dayEndHour;
    const today = new Date();

    //  Column headers 
    let colHeader = container.find('.cal-tg-header')[0];
    let headerCells;
    if (!colHeader) {
        colHeader = PART.TG_HEADER.create();
        const gutterSpacer = PART.TG_GUTTER.create();
        colHeader.append(gutterSpacer);

        headerCells = PART.TG_HEADER_CELLS.create();
        colHeader.append(headerCells);
    } else {
        colHeader = razyui(colHeader);
        headerCells = razyui(colHeader.find('.cal-tg-header-cells')[0]);
    }
    headerCells.css('--cols', numDays);

    // Reuse or create header cells
    const existingHdrCells = headerCells.children();
    for (let d = 0; d < numDays; d++) {
        const colDate = addDays(startDate, d);
        let hdr = existingHdrCells[d];
        
        if (!hdr) {
            hdr = PART.TG_COL_HEADER.create();
            const dayName = PART.TG_DAY_NAME.create();
            const dayNum = PART.TG_DAY_NUM.create();
            hdr.append(dayName)
               .append(dayNum);
            headerCells.append(hdr);
        } else {
            hdr = razyui(hdr);
            hdr.removeClass('is-today');
        }

        if (sameDay(colDate, today)) hdr.addClass('is-today');
        hdr.find('.cal-tg-day-name').text(WEEKDAYS_SHORT[colDate.getDay()]);
        hdr.find('.cal-tg-day-num').text(colDate.getDate());
    }
    // Remove extra header cells if numDays decreased
    for (let d = numDays; d < existingHdrCells.length; d++) {
        razyui(existingHdrCells[d]).detach();
    }

    //  Scrollable body 
    let scrollBody = container.find('.cal-tg-scroll')[0];
    if (!scrollBody) {
        scrollBody = PART.TG_SCROLL.create();
        container.append(scrollBody);
    } else {
        scrollBody = razyui(scrollBody);
    }

    //  Sticky top zone (header + all-day) 
    let stickyTop = scrollBody.find('.cal-tg-sticky-top')[0];
    if (!stickyTop) {
        stickyTop = PART.TG_STICKY.create();
        stickyTop.append(colHeader);
        scrollBody.append(stickyTop);
    } else {
        stickyTop = razyui(stickyTop);
    }

    //  All-day / multi-day 
    let allDay = stickyTop.find('.cal-tg-allday')[0];
    if (!allDay) {
        allDay = PART.TG_ALLDAY.create();
        const gutter = PART.TG_GUTTER.create();
        PART.TG_ALLDAY_GUTTER.apply(gutter);
        const glabel = razyui.el('span', { textContent: 'All day' });
        gutter.append(glabel);
        allDay.append(gutter);

        const grid = PART.TG_ALLDAY_GRID.create();
        allDay.append(grid);
        stickyTop.append(allDay);
    } else {
        allDay = razyui(allDay);
        allDay.find('.cal-tg-allday-grid').html('');
    }

    const rangeEndDate = addDays(startDate, numDays);
    const multiDayEvts = events.filter(ev => {
        if (sameDay(ev.start, ev.end)) return false;
        const evS = startOfDay(ev.start).getTime();
        const evE = startOfDay(ev.end).getTime();
        return evS < rangeEndDate.getTime() && evE >= startDate.getTime();
    });

    if (multiDayEvts.length > 0) {
        allDay.css('display', '');
        const grid = allDay.find('.cal-tg-allday-grid');
        grid.css('--cols', numDays);

        const bars = [];
        const startMs = startDate.getTime();
        for (const ev of multiDayEvts) {
            const evStartMs = startOfDay(ev.start).getTime();
            const evEndMs = startOfDay(ev.end).getTime();
            const sc = Math.max(0, Math.round((evStartMs - startMs) / DAY_MS));
            const ec = Math.min(numDays, Math.round((evEndMs - startMs) / DAY_MS) + 1);
            if (sc < ec) bars.push({ event: ev, startCol: sc, endCol: ec });
        }
        allocateBarLanes(bars);

        for (const bar of bars) {
            const barEl = PART.EVENT_BAR.create({ textContent: bar.event.title, 'data-cal-event-id': bar.event.id });
            barEl.css({ '--ev-color': bar.event.color, gridColumn: `${bar.startCol + 1} / ${bar.endCol + 1}` });
            barEl.css('gridRow', `${bar.lane + 1}`);
            grid.append(barEl);
        }
    } else {
        allDay.css('display', 'none');
    }

    let gridBody = scrollBody.find('.cal-tg-body')[0];
    if (!gridBody) {
        gridBody = PART.TG_BODY.create();
        scrollBody.append(gridBody);
    } else {
        gridBody = razyui(gridBody);
    }
    gridBody.css('--cols', numDays);

    // Hour rows
    const existingRows = gridBody.find('.cal-tg-row');
    let rowIndex = 0;
    for (let h = startH; h < endH; h++) {
        let row = existingRows[rowIndex];
        let cellsContainer;
        
        if (!row) {
            row = PART.TG_ROW.create();
            const label = PART.TG_TIME_LABEL.create();
            const labelSpan = razyui.el('span', { textContent: `${pad(h)}:00` });
            label.append(labelSpan);
            row.append(label);

            cellsContainer = PART.TG_CELLS.create();
            row.append(cellsContainer);
            gridBody.append(row);
        } else {
            row = razyui(row);
            cellsContainer = row.find('.cal-tg-cells');
        }

        const existingCells = cellsContainer.children();
        for (let d = 0; d < numDays; d++) {
            let cell = existingCells[d];
            const cellDate = addDays(startDate, d);
            
            if (!cell) {
                cell = PART.TG_CELL.create();
                cellsContainer.append(cell);
            } else {
                cell = razyui(cell);
                cell.removeClass('is-today');
            }

            if (sameDay(cellDate, today)) cell.addClass('is-today');
            cell.data('calDate', new Date(cellDate.getFullYear(), cellDate.getMonth(), cellDate.getDate(), h, 0).getTime());
        }
        // Remove extra cells if numDays decreased
        for (let d = numDays; d < existingCells.length; d++) {
            razyui(existingCells[d]).detach();
        }
        rowIndex++;
    }
    // Remove extra rows if startH/endH changed
    for (let i = rowIndex; i < existingRows.length; i++) {
        razyui(existingRows[i]).detach();
    }

    //  Event overlays 
    let overlay = gridBody.find('.cal-tg-overlay')[0];
    if (!overlay) {
        overlay = PART.TG_OVERLAY.create();
        gridBody.append(overlay);
    } else {
        overlay = razyui(overlay);
        overlay.html(''); // We still recreate event blocks for now, as they are highly dynamic
    }
    overlay.css('--cols', numDays);

    for (let d = 0; d < numDays; d++) {
        const colDate = addDays(startDate, d);
        const col = PART.TG_EVENT_COL.create();

        const dayEvts = getEventsForDay(events, colDate)
            .filter(ev => sameDay(ev.start, ev.end));
        dayEvts.forEach(ev => {
            const block = createTimeBlock(razyui, ev, startH, endH);
            if (block) col.append(block);
        });

        overlay.append(col);
    }

    //  Now line 
    let nowLine = gridBody.find('.cal-now-line')[0];
    if (isDateInRange(today, startDate, numDays)) {
        const now = new Date();
        const mins = now.getHours() * 60 + now.getMinutes();
        const startMin = startH * 60;
        const endMin = endH * 60;
        const pct = ((mins - startMin) / (endMin - startMin)) * 100;

        if (pct >= 0 && pct <= 100) {
            if (!nowLine) {
                nowLine = PART.NOW_LINE.create();
                gridBody.append(nowLine);
            } else {
                nowLine = razyui(nowLine);
            }
            nowLine.css('top', `${pct}%`);
        } else if (nowLine) {
            razyui(nowLine).detach();
        }
    } else if (nowLine) {
        razyui(nowLine).detach();
    }

    // Auto-scroll to ~8 AM only if it's a new container
    if (!existingContainer) {
        requestAnimationFrame(() => {
            const scrollTarget = Math.max(0, SCROLL_TARGET_HOUR - startH) * 60;
            scrollBody.prop('scrollTop', scrollTarget);
        });
    }

    return container[0];
}

